    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // 记录每个元素的位置
    vector<int> pos(n + 1);
    for (int i = 0; i < n; ++i) {
        pos[a[i]] = i;
    }

    int rounds = 1;
    for (int i = 2; i <= n; ++i) {
        // 如果当前元素的位置在前一个元素的后面，说明可以连续递增
        if (pos[i] > pos[i - 1]) {
            continue;
        } else {
            rounds++;
        }
    }

    cout << rounds << endl;
    return 0;
}

