/* 幸运印章问题 - 修正后的数学公式解法 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    long long n;
    cin >> n;

    long long k = sqrt(n);
    // 处理浮点精度问题，确保k是最大的满足k*k <=n的整数
    while (k*k > n) k--;
    while ((k+1)*(k+1) <= n) k++;

    long long res = 2 * k * (k + 1);
    long long rem = n - k*k;

    if (rem > 0) {
        if (rem <= k) {
            res += 3 * rem;
        } else {
            res += 3 * k + 2 * (rem - k);
        }
    }

    cout << res << endl;
    return 0;
}
```

