#include <bits/stdc++.h>
using namespace std;

// 函数声明
bool is_palindrome(const string& s);

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    unordered_set<string> strs;
    unordered_set<string> rev_strs;  // 存储所有字符串的反转
    vector<string> originals(n);

    for (int i = 0; i < n; ++i) {
        cin >> originals[i];
        strs.insert(originals[i]);
        string rev(originals[i].rbegin(), originals[i].rend());
        rev_strs.insert(rev);
    }

    int max_len = 0;

    for (const string& s : originals) {
        string rev_s(s.rbegin(), s.rend());

        // 情况1：完全反转匹配（s + rev_s 或 rev_s + s）
        if (strs.count(rev_s) && rev_s != s) {
