                reverse(target.begin(), target.end());
                if (strs.count(target) && target != s) {
                    max_len = max(max_len, (int)s.size() + (int)target.size());
                }
            }
        }
    }

    cout << max_len << '\n';
    return 0;
}

// 辅助函数：判断字符串是否为回文
bool is_palindrome(const string& s) {
    int left = 0, right = (int)s.size() - 1;
    while (left < right) {
        if (s[left] != s[right]) return false;
        ++left;
        --right;
    }
    return true;
}
